:host {
    display: block;
    width: 100%;
    height: 100%;
    padding: 0;
    margin: 0;
    overflow: hidden;
}

.svg-box {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    margin: 0;
    box-sizing: border-box;
    overflow: hidden;
}

.svg-box svg {
    width: 100%;
    height: 100%;
    display: block;
}

.svg-box img {
    width: 100%;
    height: 100%;
    object-fit: contain;
    display: block;
}

descriptor.controllerScript:
self.onInit = function () {
    self.ctx.svgContainer = $('#svg-container', self.ctx.$container);

    var settings = self.ctx.settings;
    self.ctx.svgValue = (settings.svgSource || '').trim();
    self.ctx.globalColor = settings.globalColor || '';
    self.ctx.specificPathIds = (settings.specificPathIds || '').trim();
    self.ctx.specificPathColor = settings.specificPathColor || '';
    self.ctx.svgLoaded = false;

    // Cargar SVG
    self.loadSvg();
};

// --- Cargar SVG (raw o URL) ---
self.loadSvg = function () {
    var svgValue = self.ctx.svgValue;
    if (!svgValue || svgValue.length === 0) return;

    if (svgValue.indexOf('<svg') !== -1) {
        // SVG crudo
        self.ctx.svgContainer.html(svgValue);
        self.ctx.svgLoaded = true;
        self.applySvgStyles();
        self.applyConditions();
    } else {
        // URL: cargar contenido
        self.loadSvgFromUrl(svgValue);
    }
};

// --- Cargar SVG desde URL e inyectar inline ---
self.loadSvgFromUrl = function (url) {
    $.get(url, function (data) {
        var svgContent;
        if (typeof data === 'string') {
            svgContent = data;
        } else {
            var svgElem = $(data).find('svg');
            if (svgElem.length > 0) {
                svgContent = svgElem.prop('outerHTML') || new XMLSerializer().serializeToString(svgElem[0]);
            }
        }

        if (svgContent && svgContent.indexOf('<svg') !== -1) {
            self.ctx.svgContainer.html(svgContent);
            self.ctx.svgLoaded = true;
            self.applySvgStyles();
            self.applyConditions();
        } else {
            // Fallback: img tag
            self.ctx.svgContainer.html('<img src="' + url + '" />');
            self.ctx.svgLoaded = false;
        }
    }).fail(function () {
        self.ctx.svgContainer.html('<img src="' + url + '" />');
        self.ctx.svgLoaded = false;
    });
};

// --- Aplicar color global y color de paths específicos ---
self.applySvgStyles = function () {
    if (!self.ctx.svgLoaded) return;

    var container = self.ctx.svgContainer;
    var shapes = 'path, circle, rect, polygon, line, polyline, ellipse';

    // Color global: cambia todos los shapes
    if (self.ctx.globalColor) {
        container.find(shapes).each(function () {
            $(this).attr('fill', self.ctx.globalColor);
            $(this).css('fill', self.ctx.globalColor);
        });
    }

    // Color de paths específicos (por ID, separados por coma)
    if (self.ctx.specificPathIds && self.ctx.specificPathColor) {
        var ids = self.ctx.specificPathIds.split(',');
        for (var i = 0; i < ids.length; i++) {
            var id = ids[i].trim();
            if (id) {
                var el = container.find('#' + id);
                if (el.length > 0) {
                    el.attr('fill', self.ctx.specificPathColor);
                    el.css('fill', self.ctx.specificPathColor);
                }
            }
        }
    }
};

// --- Aplicar condiciones basadas en telemetría ---
self.applyConditions = function () {
    if (!self.ctx.svgLoaded) return;

    var settings = self.ctx.settings;
    var container = self.ctx.svgContainer;

    // Obtener valor actual de telemetría
    var rawValue = null;
    if (
        self.ctx.defaultSubscription &&
        self.ctx.defaultSubscription.data &&
        self.ctx.defaultSubscription.data.length > 0
    ) {
        var dataKey = self.ctx.defaultSubscription.data[0];
        if (dataKey.data && dataKey.data.length > 0) {
            rawValue = dataKey.data[dataKey.data.length - 1][1];
        }
    }

    // Evaluar condiciones 1-5
    for (var i = 1; i <= 5; i++) {
        if (!settings['condEnabled' + i]) continue;

        var op = settings['condOperator' + i] || 'eq';
        var compareVal = settings['condValue' + i];
        var condColor = settings['condColor' + i];
        var condPaths = (settings['condPaths' + i] || '').trim();

        if (!condColor || !condPaths) continue;

        var match = self.evaluateCondition(rawValue, op, compareVal);

        if (match) {
            // Aplicar color a los paths especificados
            var pathIds = condPaths.split(',');
            for (var j = 0; j < pathIds.length; j++) {
                var pid = pathIds[j].trim();
                if (pid) {
                    var el = container.find('#' + pid);
                    if (el.length > 0) {
                        el.attr('fill', condColor);
                        el.css('fill', condColor);
                    }
                }
            }
        }
    }
};

// --- Comparar valor de telemetría con el valor de la condición ---
self.evaluateCondition = function (rawValue, operator, compareVal) {
    if (rawValue === null || rawValue === undefined) return false;
    if (compareVal === null || compareVal === undefined || compareVal === '') return false;

    // Convertir ambos a número si es posible, sino comparar como string
    var val = rawValue;
    var cmp = compareVal;

    // Intentar comparación numérica
    var numVal = Number(val);
    var numCmp = Number(cmp);
    var bothNumeric = !isNaN(numVal) && !isNaN(numCmp) && String(val).trim() !== '' && String(cmp).trim() !== '';

    if (bothNumeric) {
        val = numVal;
        cmp = numCmp;
    } else {
        // Comparar como strings (soporta booleanos como "true"/"false")
        val = String(val).trim().toLowerCase();
        cmp = String(cmp).trim().toLowerCase();
    }

    switch (operator) {
        case 'eq': return val == cmp;
        case 'neq': return val != cmp;
        case 'gt': return val > cmp;
        case 'lt': return val < cmp;
        case 'gte': return val >= cmp;
        case 'lte': return val <= cmp;
        default: return val == cmp;
    }
};

self.onDataUpdated = function () {
    if (!self.ctx.svgLoaded) {
        // SVG aún no cargado (posiblemente por URL async), intentar cargar
        if (!self.ctx.svgValue) return;
        self.loadSvg();
        return;
    }

    // Re-aplicar estilos base (resetear colores condicionales)
    self.applySvgStyles();
    // Re-evaluar condiciones con datos nuevos
    self.applyConditions();
};

self.onResize = function () { };

self.typeParameters = function () {
    return {
        maxDatasources: 1,
        maxDataKeys: 1,
        dataKeysOptional: true
    };
};

self.onDestroy = function () { };

